openscad:
length = 80; // [50:5:150]
width = 40; // [20:5:80]
thickness = 10; // [5:1:20]
hole_dia = 5; // [3:0.5:10]
$fn = 60;
module bracket() {
  difference() {
    union() {
      cube([width, length, thickness]);
      cube([length, width, thickness]);
    }
    translate([width/2, 15, -1]) cylinder(h=thickness+2, d=hole_dia);
    translate([width/2, length-15, -1]) cylinder(h=thickness+2, d=hole_dia);
    translate([length-15, width/2, -1]) cylinder(h=thickness+2, d=hole_dia);
  }
}
color("gray") bracket();
